-- ============================================
-- Legislacao full-site: joao-rodrigues / Camara Dados Abertos / projetos_lei
-- Coverage ampliado parcial: Lote A autoria principal Camara
-- ============================================
-- Fonte oficial: Camara dos Deputados - Dados Abertos
--   https://dadosabertos.camara.leg.br/api/v2/deputados/160571
--   https://dadosabertos.camara.leg.br/api/v2/proposicoes/{id}
--   https://dadosabertos.camara.leg.br/api/v2/proposicoes/{id}/autores
--
-- Artefato de auditoria:
--   fonte interna de curadoria
--
-- Coverage:
--   coverage_id    = joao-rodrigues-camara-autoria-principal-ampliado-parcial-lote-a-20260506
--   coverage_scope = inventario_ampliado_parcial_camara_autoria_principal_lote_a_20260506
--
-- Filtro factual: das 154 rows Camara legacy existentes, somente 56
-- foram marcadas com coverage_id porque a API oficial confirmou
-- idDeputado=160571, tipo Deputado(a), ordemAssinatura=1.
-- 98 rows permanecem sem coverage por coautoria/sem autoria verificavel.
--
-- Esta migration NAO escreve em legislacao_mandato_executivo.
-- Esta migration NAO insere, deleta ou trunca rows.
-- ============================================

DO $$
DECLARE
  cand_id uuid;
  total_pl int;
  target_present int;
  target_with_other_coverage int;
  lme_count int;
BEGIN
  SELECT id INTO cand_id FROM candidatos WHERE slug = 'joao-rodrigues';

  IF cand_id IS NULL THEN
    RAISE NOTICE 'joao-rodrigues: candidato ausente neste banco local/CI minimo; coverage Camara pulado';
    RETURN;
  END IF;

  SELECT count(*) INTO total_pl FROM projetos_lei WHERE candidato_id = cand_id;
  IF total_pl <> 154 THEN
    RAISE EXCEPTION 'Pre-condicao joao-rodrigues: esperadas 154 rows legacy em projetos_lei, encontradas %', total_pl;
  END IF;

  SELECT count(*) INTO target_present
  FROM projetos_lei
  WHERE candidato_id = cand_id
    AND fonte = 'Camara'
    AND proposicao_id_api IN ('2162789', '2161113', '2161117', '2161112', '2161116', '2158236', '2161114', '2144784', '2142100', '2137991', '2083362', '2146117', '2145954', '2161115', '2156512', '2146116', '2142101', '2139434', '2126502', '2148319', '2144789', '2136961', '2093628', '2090128', '2084336', '2082966', '2058512', '2056383', '2135230', '2111533', '2092949', '2089063', '2083974', '2081855', '2057565', '2056183', '2132938', '2124913', '2120074', '2111530', '2091397', '2087720', '2083972', '2081854', '2057564', '2056182', '2090142', '2087068', '2083361', '2075374', '2117997', '2090191', '2087334', '2081853', '2056104', '2144778');
  IF target_present <> 56 THEN
    RAISE EXCEPTION 'Pre-condicao joao-rodrigues: esperadas 56 rows alvo Camara presentes, encontradas %', target_present;
  END IF;

  SELECT count(*) INTO target_with_other_coverage
  FROM projetos_lei
  WHERE candidato_id = cand_id
    AND proposicao_id_api IN ('2162789', '2161113', '2161117', '2161112', '2161116', '2158236', '2161114', '2144784', '2142100', '2137991', '2083362', '2146117', '2145954', '2161115', '2156512', '2146116', '2142101', '2139434', '2126502', '2148319', '2144789', '2136961', '2093628', '2090128', '2084336', '2082966', '2058512', '2056383', '2135230', '2111533', '2092949', '2089063', '2083974', '2081855', '2057565', '2056183', '2132938', '2124913', '2120074', '2111530', '2091397', '2087720', '2083972', '2081854', '2057564', '2056182', '2090142', '2087068', '2083361', '2075374', '2117997', '2090191', '2087334', '2081853', '2056104', '2144778')
    AND coverage_id IS NOT NULL
    AND coverage_id <> 'joao-rodrigues-camara-autoria-principal-ampliado-parcial-lote-a-20260506';
  IF target_with_other_coverage <> 0 THEN
    RAISE EXCEPTION 'Pre-condicao joao-rodrigues: % rows alvo ja tem coverage_id divergente', target_with_other_coverage;
  END IF;

  SELECT count(*) INTO lme_count FROM legislacao_mandato_executivo WHERE candidato_id = cand_id;
  IF lme_count <> 0 THEN
    RAISE EXCEPTION 'Pre-condicao joao-rodrigues: legislacao_mandato_executivo deve permanecer 0, encontrado %', lme_count;
  END IF;
END $$;

